// Graph: 0-1, 1-2, 2-0 (a cycle!)
// Naive BFS from 0 without tracking visited nodes could bounce
// between 0, 1, 2 endlessly, since each has a path back to the others.

import java.util.*;

public class Main {
    static void bfs(List<List<Integer>> adjList, int start) {
        boolean[] visited = new boolean[adjList.size()];
        Queue<Integer> queue = new LinkedList<>();

        queue.offer(start);
        visited[start] = true;

        while (!queue.isEmpty()) {
            int current = queue.poll();
            System.out.print(current + " ");

            for (int neighbor : adjList.get(current)) {
                if (!visited[neighbor]) {
                    visited[neighbor] = true; // mark BEFORE enqueuing
                    queue.offer(neighbor);
                }
            }
        }
    }

    public static void main(String[] args) {
        int n = 5;
        List<List<Integer>> adjList = new ArrayList<>();
        for (int i = 0; i < n; i++) adjList.add(new ArrayList<>());

        int[][] edges = {{0,1}, {0,2}, {1,3}, {2,4}, {3,4}};
        for (int[] e : edges) {
            adjList.get(e[0]).add(e[1]);
            adjList.get(e[1]).add(e[0]);
        }

        bfs(adjList, 0);
    }
}

import java.util.*;

public class Main {
    static int shortestPath(List<List<Integer>> adjList, int start, int target) {
        boolean[] visited = new boolean[adjList.size()];
        Queue<Integer> queue = new LinkedList<>();
        int[] distance = new int[adjList.size()];

        queue.offer(start);
        visited[start] = true;

        while (!queue.isEmpty()) {
            int current = queue.poll();
            if (current == target) {
                return distance[current];
            }

            for (int neighbor : adjList.get(current)) {
                if (!visited[neighbor]) {
                    visited[neighbor] = true;
                    distance[neighbor] = distance[current] + 1;
                    queue.offer(neighbor);
                }
            }
        }
        return -1; // unreachable
    }

    public static void main(String[] args) {
        int n = 5;
        List<List<Integer>> adjList = new ArrayList<>();
        for (int i = 0; i < n; i++) adjList.add(new ArrayList<>());

        int[][] edges = {{0,1}, {0,2}, {1,3}, {2,4}, {3,4}};
        for (int[] e : edges) {
            adjList.get(e[0]).add(e[1]);
            adjList.get(e[1]).add(e[0]);
        }

        System.out.println(shortestPath(adjList, 0, 4));
    }
}

